using System;
using System.Threading.Tasks;
using Azure.Identity;
using Azure.ResourceManager;
using Azure.ResourceManager.ContainerServiceFleet;
using Azure.ResourceManager.ContainerServiceFleet.Models;
using Azure.ResourceManager.Resources;
using NUnit.Framework;

namespace Azure.ResourceManager.ContainerServiceFleet.Tests.Samples
{
    public class Sample1_FleetOperations : SamplesBase<ContainerServiceFleetManagementTestEnvironment>
    {
        [Test]
        [SyncOnly]
        [Ignore("Only verifying that the sample builds")]
        public async Task CreateFleet()
        {
            #region Snippet:CreateFleet
            ArmClient client = new ArmClient(new DefaultAzureCredential());

            string subscriptionId = "<subscription-id>";
            string resourceGroupName = "<resource-group-name>";
            string fleetName = "<fleet-name>";

            ResourceGroupResource resourceGroup = await client
                .GetSubscriptionResource(new ResourceIdentifier($"/subscriptions/{subscriptionId}"))
                .GetResourceGroupAsync(resourceGroupName);

            ContainerServiceFleetCollection fleets = resourceGroup.GetContainerServiceFleets();

            ContainerServiceFleetData fleetData = new ContainerServiceFleetData(AzureLocation.EastUS);

            ArmOperation<ContainerServiceFleetResource> operation = await fleets.CreateOrUpdateAsync(
                WaitUntil.Completed,
                fleetName,
                fleetData);

            ContainerServiceFleetResource fleet = operation.Value;
            Console.WriteLine($"Created Fleet: {fleet.Data.Name}");
            #endregion
        }

        [Test]
        [SyncOnly]
        [Ignore("Only verifying that the sample builds")]
        public async Task AddFleetMember()
        {
            #region Snippet:AddFleetMember
            ArmClient client = new ArmClient(new DefaultAzureCredential());

            ResourceIdentifier fleetId = ContainerServiceFleetResource.CreateResourceIdentifier(
                "<subscription-id>",
                "<resource-group-name>",
                "<fleet-name>");

            ContainerServiceFleetResource fleet = client.GetContainerServiceFleetResource(fleetId);

            ContainerServiceFleetMemberCollection members = fleet.GetContainerServiceFleetMembers();

            string aksClusterResourceId = "/subscriptions/<subscription-id>/resourceGroups/<rg>/providers/Microsoft.ContainerService/managedClusters/<cluster-name>";

            ContainerServiceFleetMemberData memberData = new ContainerServiceFleetMemberData
            {
                ClusterResourceId = new ResourceIdentifier(aksClusterResourceId)
            };

            ArmOperation<ContainerServiceFleetMemberResource> operation = await members.CreateOrUpdateAsync(
                WaitUntil.Completed,
                "<member-name>",
                memberData);

            ContainerServiceFleetMemberResource member = operation.Value;
            Console.WriteLine($"Added member: {member.Data.Name}");
            #endregion
        }

        [Test]
        [SyncOnly]
        [Ignore("Only verifying that the sample builds")]
        public async Task CreateUpdateRun()
        {
            #region Snippet:CreateUpdateRun
            ArmClient client = new ArmClient(new DefaultAzureCredential());

            ResourceIdentifier fleetId = ContainerServiceFleetResource.CreateResourceIdentifier(
                "<subscription-id>",
                "<resource-group-name>",
                "<fleet-name>");

            ContainerServiceFleetResource fleet = client.GetContainerServiceFleetResource(fleetId);

            ContainerServiceFleetUpdateRunData updateRunData = new ContainerServiceFleetUpdateRunData
            {
                ManagedClusterUpdate = new ContainerServiceFleetManagedClusterUpdate(
                    new ContainerServiceFleetManagedClusterUpgradeSpec(
                        ContainerServiceFleetManagedClusterUpgradeType.Full)
                    {
                        KubernetesVersion = "1.30"
                    })
            };

            ArmOperation<ContainerServiceFleetUpdateRunResource> operation = await fleet
                .GetContainerServiceFleetUpdateRuns()
                .CreateOrUpdateAsync(WaitUntil.Completed, "<update-run-name>", updateRunData);

            ContainerServiceFleetUpdateRunResource updateRun = operation.Value;
            Console.WriteLine($"Created update run: {updateRun.Data.Name}");
            #endregion
        }

        [Test]
        [SyncOnly]
        [Ignore("Only verifying that the sample builds")]
        public async Task CreateGate()
        {
            #region Snippet:CreateGate
            ArmClient client = new ArmClient(new DefaultAzureCredential());

            ResourceIdentifier fleetId = ContainerServiceFleetResource.CreateResourceIdentifier(
                "<subscription-id>",
                "<resource-group-name>",
                "<fleet-name>");

            ContainerServiceFleetResource fleet = client.GetContainerServiceFleetResource(fleetId);

            ContainerServiceFleetGateData gateData = new ContainerServiceFleetGateData();

            ArmOperation<ContainerServiceFleetGateResource> operation = await fleet
                .GetContainerServiceFleetGates()
                .CreateOrUpdateAsync(WaitUntil.Completed, "<gate-name>", gateData);

            ContainerServiceFleetGateResource gate = operation.Value;
            Console.WriteLine($"Created gate: {gate.Data.Name}");
            #endregion
        }

        [Test]
        [SyncOnly]
        [Ignore("Only verifying that the sample builds")]
        public async Task CreateManagedNamespace()
        {
            #region Snippet:CreateManagedNamespace
            ArmClient client = new ArmClient(new DefaultAzureCredential());

            ResourceIdentifier fleetId = ContainerServiceFleetResource.CreateResourceIdentifier(
                "<subscription-id>",
                "<resource-group-name>",
                "<fleet-name>");

            ContainerServiceFleetResource fleet = client.GetContainerServiceFleetResource(fleetId);

            ContainerServiceFleetManagedNamespaceData nsData = new ContainerServiceFleetManagedNamespaceData();

            ArmOperation<ContainerServiceFleetManagedNamespaceResource> operation = await fleet
                .GetContainerServiceFleetManagedNamespaces()
                .CreateOrUpdateAsync(WaitUntil.Completed, "<namespace-name>", nsData);

            ContainerServiceFleetManagedNamespaceResource managedNamespace = operation.Value;
            Console.WriteLine($"Created managed namespace: {managedNamespace.Data.Name}");
            #endregion
        }
    }
}
```

